import{_ as t,o as i,c as n,ag as r}from"./chunks/framework.NIzFHKo_.js";const g=JSON.parse('{"title":"Founding Principles","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/10_governance/10_principles/_index.md","filePath":"10_core/10_governance/10_principles/_index.md"}'),a={name:"10_core/10_governance/10_principles/_index.md"};function o(s,e,l,c,d,p){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="founding-principles" tabindex="-1">Founding Principles <a class="header-anchor" href="#founding-principles" aria-label="Permalink to &quot;Founding Principles&quot;">​</a></h1><p>QiAccess Start inherits the strongest parts of the QiOS constitutional model while locking the active portal doctrine to real daily use.</p><h2 id="retained-constitutional-principles" tabindex="-1">Retained Constitutional Principles <a class="header-anchor" href="#retained-constitutional-principles" aria-label="Permalink to &quot;Retained Constitutional Principles&quot;">​</a></h2><p>These remain non-negotiable:</p><ol><li><strong>One canonical identity per object</strong></li><li><strong>One clear home per concern</strong></li><li><strong>Metadata precedes automation</strong></li><li><strong>Lineage survives transformation</strong></li><li><strong>Human-readable naming with machine-stable identity</strong></li><li><strong>Local-first where appropriate; cloud-backed where strategic</strong></li><li><strong>Systems compose cleanly without collision</strong></li></ol><h2 id="qiaccess-start-operating-principles" tabindex="-1">QiAccess Start Operating Principles <a class="header-anchor" href="#qiaccess-start-operating-principles" aria-label="Permalink to &quot;QiAccess Start Operating Principles&quot;">​</a></h2><p>These govern the active portal:</p><ol><li><strong>QiAccess is the portal.</strong> The app is the front door, not an abstract platform diagram.</li><li><strong>Seven roots only.</strong> Home, Start, Capture, Knowledge, Memory, Insights, and System are the top-level navigation contract.</li><li><strong>Capture is first-class.</strong> If offloading thoughts, files, or observations is slow, the system is failing its primary job.</li><li><strong>System stays nested.</strong> Admin, infrastructure, storage, blueprint, and diagnostics belong under System rather than becoming parallel roots.</li><li><strong>Knowledge, Memory, and Insights are different.</strong> Knowledge is curated source material, Memory is continuity and context, Insights are derived interpretation.</li><li><strong>Derived AI is never truth by itself.</strong> Every summary, link, pattern, or suggestion must point back to a source.</li><li><strong>Legacy is preserved by quarantine, not by co-owning doctrine.</strong> Older platform and tenant models may be referenced, but they do not define the active runtime unless promoted again on purpose.</li></ol><h2 id="non-negotiable-rules" tabindex="-1">Non-Negotiable Rules <a class="header-anchor" href="#non-negotiable-rules" aria-label="Permalink to &quot;Non-Negotiable Rules&quot;">​</a></h2><ul><li>Important files and system records need clear ownership.</li><li>Identity cannot be redefined downstream.</li><li>Logic must not be silently duplicated across apps, workers, and scripts.</li><li>Automation requires minimum structure first.</li><li>Derived layers cannot become truth sources.</li><li>Informal notes cannot override active doctrine.</li><li>Legacy material must be labeled before reuse.</li></ul><h2 id="retained-constitutional-rules" tabindex="-1">Retained Constitutional Rules <a class="header-anchor" href="#retained-constitutional-rules" aria-label="Permalink to &quot;Retained Constitutional Rules&quot;">​</a></h2><ol><li>one canonical identity per object</li><li>one clear home per concern</li><li>metadata precedes automation</li><li>lineage survives transformation</li><li>derived systems are not truth sources</li><li>exposure boundaries must be explicit</li><li>structural changes earn ADR review</li></ol>',12)])])}const m=t(a,[["render",o]]);export{g as __pageData,m as default};
